{"content": """"
Correlation Filter — Cegah posisi correlated yang saling merugikan.

RULE:
  - Korelasi POSITIF TINGGI (>0.6) + arah SAMA (LONG-LONG / SHORT-SHORT) → SKIP
  - Korelasi POSITIF TINGGI (>0.6) + arah BERLAWANAN → OK (natural hedge)
  - Korelasi RENDAH (<0.6) → OK, boleh arah apapun
"""
import math
import time
from datetime import datetime


class CorrelationFilter:
    """Real-time correlation calculator + trade filter."""

    def __init__(self, exchange, symbols, lookback=50, log_fn=None):
        self.ex = exchange
        self.symbols = symbols
        self.lookback = lookback
        self.log = log_fn or (lambda msg, tag='INFO': print(f"[{tag}] {msg}"))

        self.closes = {}       # {symbol: [close_prices]}
        self.returns = {}      # {symbol: [returns]}
        self.matrix = {}       # {(sym1, sym2): correlation}
        self.last_update = 0
        self.update_interval = 300  # Update setiap 5 menit

    def refresh(self):
        """Fetch candle data & hitung correlation matrix."""
        now = time.time()
        if now - self.last_update < self.update_interval:
            return

        self.log("🔄 Refreshing correlation matrix...", 'CORR')

        # Fetch closes
        for sym in self.symbols:
            candles = self.ex.get_candles(sym, '1h', self.lookback + 1)
            if candles and len(candles) >= self.lookback:
                self.closes[sym] = [c['close'] for c in candles[-self.lookback:]]
                prices = self.closes[sym]
                self.returns[sym] = [
                    (prices[i] - prices[i - 1]) / prices[i - 1]
                    for i in range(1, len(prices))
                ]

        # Hitung correlation matrix
        self.matrix = {}
        for i, s1 in enumerate(self.symbols):
            for s2 in self.symbols[i + 1:]:
                if s1 in self.returns and s2 in self.returns:
                    c = self._corr(self.returns[s1], self.returns[s2])
                    self.matrix[(s1, s2)] = c
                    self.matrix[(s2, s1)] = c

        self.last_update = now
        self._log_matrix()

    def _corr(self, x, y):
        """Pearson correlation coefficient."""
        n = min(len(x), len(y))
        if n < 10:
            return 0.0
        x, y = x[-n:], y[-n:]

        mx = sum(x) / n
        my = sum(y) / n

        sx = math.sqrt(sum((xi - mx) ** 2 for xi in x) / n)
        sy = math.sqrt(sum((yi - my) ** 2 for yi in y) / n)

        if sx == 0 or sy == 0:
            return 0.0

        cov = sum((x[i] - mx) * (y[i] - my) for i in range(n)) / n
        return cov / (sx * sy)

    def get_correlation(self, sym1, sym2):
        """Get correlation between two symbols."""
        if sym1 == sym2:
            return 1.0
        return self.matrix.get((sym1, sym2), 0.0)

    def check_signal(self, new_symbol, new_direction, active_positions):
        """
        Check apakah signal baru boleh dieksekusi.

        Args:
            new_symbol: Symbol yang mau dibuka
            new_direction: 'LONG' atau 'SHORT'
            active_positions: list of dict {symbol, direction}

        Returns:
            (allowed: bool, reason: str)
        """
        self.refresh()

        for pos in active_positions:
            pos_sym = pos['symbol']
            pos_dir = pos['direction']

            if pos_sym == new_symbol:
                continue

            corr = self.get_correlation(new_symbol, pos_sym)

            if corr > 0.6:
                # Korelasi tinggi — cek arah
                if pos_dir == new_direction:
                    # SAMA arah = BAHAYA, salah satu pasti rugi
                    return False, (
                        f"❌ SKIP: {new_symbol} {new_direction} "
                        f"korrelasi {corr:+.2f} dengan {pos_sym} {pos_dir} "
                        f"(arah sama = double risk)"
                    )
                else:
                    # Berlawanan = OK (natural hedge)
                    self.log(
                        f"✅ {new_symbol} {new_direction} vs {pos_sym} {pos_dir} "
                        f"— korelasi {corr:+.2f} (opposing = hedge)",
                        'CORR'
                    )

            elif corr > 0.4:
                # Korelasi medium — warning tapi izinkan
                if pos_dir == new_direction:
                    self.log(
                        f"⚠️ {new_symbol} {new_direction} "
                        f"medium correlation {corr:+.2f} dengan {pos_sym} {pos_dir}",
                        'CORR'
                    )

        return True, "OK"

    def get_portfolio_correlation_risk(self, active_positions):
        """
        Hitung total correlation risk portfolio.
        Returns: (risk_score: float 0-1, details: list)
        """
        self.refresh()

        if len(active_positions) < 2:
            return 0.0, ["Single position — no correlation risk"]

        details = []
        total_corr = 0
        count = 0

        for i, pos1 in enumerate(active_positions):
            for pos2 in active_positions[i + 1:]:
                corr = self.get_correlation(pos1['symbol'], pos2['symbol'])

                same_dir = pos1['direction'] == pos2['direction']
                risk = corr if same_dir else -corr * 0.5  # Opposing = reduce risk

                total_corr += risk
                count += 1

                tag = "🔴" if risk > 0.5 else ("🟡" if risk > 0 else "🟢")
                details.append(
                    f"{tag} {pos1['symbol']} {pos1['direction']} ↔ "
                    f"{pos2['symbol']} {pos2['direction']}: "
                    f"corr={corr:+.2f}, risk={risk:+.2f}"
                )

        avg_risk = total_corr / count if count > 0 else 0
        return avg_risk, details

    def _log_matrix(self):
        """Log correlation matrix."""
        if not self.matrix:
            return

        self.log("📊 Correlation Matrix:", 'CORR')
        for (s1, s2), c in sorted(self.matrix.items()):
            if s1 < s2:  # Avoid duplicates
                tag = "🔴" if c > 0.7 else ("🟡" if c > 0.4 else "🟢")
                self.log(f"  {tag} {s1:>10s} ↔ {s2:<10s}: {c:+.3f}", 'CORR')
